+namespace DocSummary.Services;
+
+/// <summary>
+/// Extractive summarizer that scores sentences by word frequency
+/// and returns the top-ranked ones in their original order.
+/// </summary>
+public class DocumentSummarizer
+{
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a","an","the","and","or","but","is","are","was","were","be","been",
+        "being","have","has","had","do","does","did","will","would","shall",
+        "should","may","might","must","can","could","i","you","he","she","it",
+        "we","they","me","him","her","us","them","my","your","his","its","our",
+        "their","this","that","these","those","in","on","at","to","for","of",
+        "with","by","from","as","into","about","between","through","during",
+        "before","after","above","below","not","no","nor","so","if","then",
+        "than","too","very","just","also","more","most","own","same","such",
+        "only","other","each","every","all","both","few","many","some","any",
+        "when","where","while","how","what","which","who","whom","why"
+    };
+
+    public string Summarize(string text, int maxSentences)
+    {
+        var sentences = SplitSentences(text);
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = BuildWordFrequencies(sentences);
+        var scored = sentences
+            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
+            .ToList();
+
+        var topSentences = scored
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Sentence);
+
+        return string.Join(" ", topSentences);
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
+        var raw = System.Text.RegularExpressions.Regex
+            .Split(text, @"(?<=[.!?])\s+");
+
+        return raw
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in Tokenize(sentence))
+            {
+                if (!StopWords.Contains(word))
+                    freq[word] = freq.TryGetValue(word, out var c) ? c + 1 : 1;
+            }
+        }
+
+        return freq;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> freq)
+    {
+        var words = Tokenize(sentence);
+        if (words.Count == 0) return 0;
+
+        double score = 0;
+        foreach (var word in words)
+        {
+            if (freq.TryGetValue(word, out var f))
+                score += f;
+        }
+
+        return score / words.Count;
+    }
+
+    private static List<string> Tokenize(string text)
+    {
+        return System.Text.RegularExpressions.Regex
+            .Matches(text, @"\w+")
+            .Select(m => m.Value)
+            .ToList();
+    }
+}
